export default "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>TeamManager</title>\n    <style>\n        :root{--font:'Inter',system-ui,-apple-system,sans-serif;--mono:'SF Mono','Cascadia Code',monospace;--bg-0:#f0f4f8;--bg-1:#fff;--bg-2:#f7f8fb;--bg-3:#edf0f5;--bd:#dfe3ea;--t1:#1a2332;--t2:#4a5568;--t3:#8899aa;--acc:#2563eb;--acc-l:#3b82f6;--acc-bg:rgba(37,99,235,.06);--r:8px;--rl:12px;--sh:0 1px 3px rgba(0,0,0,.06),0 6px 16px rgba(0,0,0,.04);--grn:#16a34a;--grn-bg:#ecfdf5;--grn-bd:#bbf7d0;--red:#dc2626;--red-bg:#fef2f2;--red-bd:#fecaca;--amber:#d97706;--amber-bg:#fffbeb;--amber-bd:#fde68a}\n        *{box-sizing:border-box;margin:0;padding:0}\n        body{font-family:var(--font);background:var(--bg-0);color:var(--t1);-webkit-font-smoothing:antialiased}\n        body.no-scroll{overflow:hidden}\n        /* SETUP */\n        #setup{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:40px 20px;gap:24px;background:linear-gradient(160deg,#f0f4f8 0%,#e8edf5 100%)}\n        #setup h1{font-size:30px;font-weight:800;letter-spacing:-.02em}\n        #setup h1 .ac{color:var(--acc)}\n        .setup-card{background:var(--bg-1);border:1px solid var(--bd);border-radius:16px;padding:36px 44px;text-align:center;cursor:pointer;transition:all .25s;box-shadow:0 2px 8px rgba(0,0,0,.04);max-width:380px;width:100%}\n        .setup-card:hover{border-color:var(--acc);box-shadow:0 8px 30px rgba(37,99,235,.12);transform:translateY(-3px)}\n        .setup-err{color:var(--red);font-size:13px;display:none}\n        /* BUTTONS */\n        .btn{padding:7px 16px;font-family:var(--font);font-size:13px;font-weight:600;border-radius:var(--r);cursor:pointer;border:1px solid var(--bd);background:var(--bg-1);color:var(--t2);transition:all 100ms}\n        .btn:hover{background:var(--bg-2)}\n        .btn-p{background:var(--acc);color:#fff;border-color:var(--acc)}.btn-p:hover{background:#1d4ed8}\n        .btn-sm{padding:4px 10px;font-size:12px}\n        /* APP */\n        #app{display:none}\n        .toolbar{display:flex;align-items:center;gap:14px;padding:10px 28px;background:var(--bg-1);border-bottom:1px solid var(--bd);position:sticky;top:0;z-index:100}\n        .toolbar h2{font-size:15px;font-weight:800;white-space:nowrap}.toolbar h2 .ac{color:var(--acc)}\n        .view-toggle{display:inline-flex;background:var(--bg-3);border-radius:var(--r);padding:2px;gap:2px}\n        .vtb{display:inline-flex;align-items:center;gap:4px;padding:5px 12px;font-family:var(--font);font-size:12px;font-weight:600;border:none;border-radius:6px;cursor:pointer;background:transparent;color:var(--t3);transition:all 150ms}\n        .vtb:hover{color:var(--t2)}.vtb.active{background:var(--bg-1);color:var(--t1);box-shadow:0 1px 3px rgba(0,0,0,.08)}\n        .vtb svg{width:13px;height:13px}\n        .search-wrap{position:relative;flex:1;max-width:280px}\n        .search-wrap svg{position:absolute;left:9px;top:50%;transform:translateY(-50%);width:14px;height:14px;color:var(--t3);pointer-events:none}\n        .search-input{width:100%;padding:6px 28px 6px 30px;font-family:var(--font);font-size:12px;border:1px solid var(--bd);border-radius:var(--r);background:var(--bg-2);color:var(--t1)}\n        .search-input:focus{outline:none;border-color:var(--acc);background:var(--bg-1)}\n        .search-clear{display:none;position:absolute;right:6px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--t3);font-size:15px;cursor:pointer;padding:1px 4px}\n        .search-wrap.has-q .search-clear{display:block}\n        .fb{font-size:10px;background:var(--bg-3);color:var(--t3);padding:2px 8px;border-radius:20px;font-weight:600;margin-left:auto}\n        /* FILTERS */\n        .filter-bar{padding:8px 24px;background:var(--bg-2);border-bottom:1px solid var(--bd);display:flex;align-items:flex-end;gap:10px;flex-wrap:wrap}\n        .fg-item{display:flex;flex-direction:column;gap:2px}\n        .fg-item label{font-size:10px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.05em}\n        .fg-item select,.fg-item input{padding:5px 8px;font-family:var(--font);font-size:12px;background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);min-width:100px}\n        .ms-wrap{position:relative}\n        .ms-btn{padding:5px 10px;font-family:var(--font);font-size:12px;background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);cursor:pointer;min-width:110px;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n        .ms-btn:hover{border-color:var(--acc)}\n        .ms-drop{display:none;position:absolute;top:100%;left:0;margin-top:4px;background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);box-shadow:0 8px 24px rgba(0,0,0,.12);z-index:200;min-width:140px;max-height:220px;overflow-y:auto;padding:2px 0}\n        .ms-drop.open{display:block}\n        .ms-drop label{display:flex;align-items:center;gap:0;padding:0 10px;font-size:12px;color:var(--t1);cursor:pointer;white-space:nowrap;height:28px}\n        .ms-drop label:hover{background:var(--bg-2)}\n        .ms-drop input{width:13px;height:13px;accent-color:var(--acc);flex-shrink:0;margin:0 6px 0 0}\n        /* STATS */\n        .stats-bar{padding:10px 28px;display:flex;gap:20px;background:var(--bg-1);border-bottom:1px solid var(--bd)}\n        .stat{font-size:12px;color:var(--t3)}.stat b{color:var(--t1);font-weight:700}\n        /* PATIENT CARDS */\n        .cards{padding:20px 28px;display:flex;flex-direction:column;gap:12px}\n        .p-card{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--rl);overflow:hidden;cursor:pointer;transition:all 180ms;box-shadow:0 1px 4px rgba(0,0,0,.04)}\n        .p-card:hover{border-color:var(--acc-l);box-shadow:0 4px 20px rgba(37,99,235,.1)}\n        .p-card-header{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;border-bottom:1px solid var(--bd)}\n        .p-card-name{font-size:17px;font-weight:700;color:var(--t1);letter-spacing:-.01em}\n        .p-card-id{font-family:var(--mono);font-size:11px;color:var(--t3)}\n        .p-card-admission{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;background:var(--bg-2);gap:16px}\n        .p-card-dates{display:flex;align-items:center;gap:10px}\n        .p-date-block{text-align:center}\n        .p-date-label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3);margin-bottom:2px}\n        .p-date-val{font-size:14px;font-weight:600;color:var(--t1);font-family:var(--mono);white-space:nowrap}\n        .p-date-arrow{font-size:16px;color:var(--t3)}\n        .p-card-status{font-size:12px;font-weight:700;padding:5px 12px;border-radius:6px;white-space:nowrap}\n        .p-status-ok{background:var(--acc-bg);color:var(--acc);border:1px solid rgba(37,99,235,.2)}\n        .p-status-urg{background:var(--red-bg);color:var(--red);border:1px solid var(--red-bd)}\n        .p-status-warn{background:var(--amber-bg);color:var(--amber);border:1px solid var(--amber-bd)}\n        .p-card-details{display:flex;flex-wrap:wrap;gap:4px 16px;padding:10px 20px}\n        .p-field{display:flex;align-items:center;gap:4px;font-size:12px}\n        .p-field-l{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3)}\n        .p-field-v{color:var(--t1)}\n        .p-card-bottom{border-top:1px solid var(--bd);padding:8px 20px;display:flex;align-items:center;gap:10px;background:var(--bg-2)}\n        .p-team{font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;background:var(--acc-bg);color:var(--acc);border:1px solid rgba(37,99,235,.15)}\n        .p-admits-pill{font-size:10px;font-weight:600;color:var(--t3);padding:2px 8px;background:var(--bg-3);border-radius:4px}\n        .p-notes{font-size:11px;color:var(--t3);margin-left:auto}\n        .p-badges{display:flex;gap:4px}\n        .p-badge{font-size:9px;font-weight:700;padding:2px 6px;border-radius:3px}\n        .p-badge-snp{background:var(--amber-bg);color:var(--amber);border:1px solid var(--amber-bd)}\n        .tier-badge{font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;display:inline-block}\n        .tier-gold{background:#fef3c7;color:#b45309;border:1px solid #fde68a}\n        .tier-silver{background:#f1f5f9;color:#475569;border:1px solid #cbd5e1}\n        .tier-bronze{background:#fef2e8;color:#9a3412;border:1px solid #fed7aa}\n        .tier-copper{background:#fce7e7;color:#b91c1c;border:1px solid #fca5a5}\n        .tier-steel{background:#e5e7eb;color:#374151;border:1px solid #9ca3af}\n        .copy-id{background:none;border:none;cursor:pointer;color:var(--t3);font-size:12px;padding:0 2px;vertical-align:middle}\n        .copy-id:hover{color:var(--acc)}\n        /* TOC ROW */\n        .p-toc-row{display:flex;align-items:center;gap:12px;padding:10px 20px;border-top:1px solid var(--bd);background:var(--bg-1)}\n        .p-toc-date{display:flex;align-items:center;gap:6px;font-size:12px}\n        .p-toc-date-label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3)}\n        .p-toc-date-val{font-weight:600;color:var(--acc);cursor:pointer;border-bottom:1px dashed var(--acc)}\n        .p-toc-date-val:hover{color:#1d4ed8}\n        .p-toc-kept{font-size:11px;font-weight:600;padding:3px 8px;border-radius:4px;cursor:pointer}\n        .p-kept-expected{background:#eff6ff;color:#3b82f6;border:1px solid #bfdbfe}\n        .p-kept-kept{background:var(--grn-bg);color:var(--grn);border:1px solid var(--grn-bd)}\n        .p-kept-noshow{background:var(--red-bg);color:var(--red);border:1px solid var(--red-bd)}\n        .p-kept-cancelled{background:var(--bg-3);color:var(--t3);border:1px solid var(--bd)}\n        .p-kept-none{background:var(--bg-3);color:var(--t3);border:1px dashed var(--bd)}\n        /* INLINE POPOVER */\n        .pop{position:fixed;z-index:600;background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);box-shadow:0 8px 30px rgba(0,0,0,.15);padding:6px 0;min-width:140px;animation:mIn .1s}\n        .pop-item{padding:7px 14px;font-size:13px;color:var(--t1);cursor:pointer}\n        .pop-item:hover{background:var(--bg-2)}\n        .pop-item.active{color:var(--acc);font-weight:600}\n        .pop-date{padding:8px 12px}\n        .pop-date input{width:100%;padding:6px 8px;font-family:var(--font);font-size:13px;border:1px solid var(--bd);border-radius:var(--r)}\n        .empty-state{text-align:center;padding:60px;color:var(--t3)}\n        /* MODALS */\n        .mo{position:fixed;inset:0;background:rgba(26,35,50,.5);backdrop-filter:blur(4px);display:flex;align-items:center;justify-content:center;z-index:500;opacity:0;pointer-events:none;transition:opacity .15s}\n        .mo.open{opacity:1;pointer-events:auto}\n        .modal{background:var(--bg-1);border-radius:var(--rl);box-shadow:0 20px 60px rgba(0,0,0,.18);width:calc(100% - 40px);overflow:hidden;animation:mIn .15s}\n        @keyframes mIn{from{transform:translateY(8px);opacity:0}to{transform:none;opacity:1}}\n        .mh{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;border-bottom:1px solid var(--bd)}\n        .mh h2{font-size:15px;font-weight:700}.mx{background:none;border:none;font-size:22px;color:var(--t3);cursor:pointer;line-height:1}.mx:hover{color:var(--t1)}\n        .mf{display:flex;justify-content:flex-end;gap:8px;padding:12px 20px;border-top:1px solid var(--bd);background:var(--bg-2)}\n        /* PATIENT MODAL */\n        .pm{max-width:960px;height:85vh;display:flex;flex-direction:column}\n        .pm-header{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);color:#fff;padding:20px 24px;flex-shrink:0}\n        .pm-name{font-size:24px;font-weight:800;margin-bottom:6px;letter-spacing:-.01em}\n        .pm-details{display:flex;flex-wrap:wrap;gap:5px 18px}\n        .pm-item{display:flex;align-items:center;gap:4px;font-size:12px}\n        .pm-lbl{color:rgba(255,255,255,.55);font-weight:700;text-transform:uppercase;letter-spacing:.04em;font-size:10px}\n        .pm-val{color:#fff;font-family:var(--mono);font-size:12px}\n        .pm-copy{background:none;border:none;cursor:pointer;color:rgba(255,255,255,.4);font-size:13px}.pm-copy:hover{color:#fff}\n        .pm-body{flex:1;overflow:hidden;display:flex}\n        .pm-admissions{width:320px;border-right:1px solid var(--bd);overflow-y:auto;flex-shrink:0;background:var(--bg-2)}\n        .pm-admit-hdr{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);padding:12px 16px;border-bottom:1px solid var(--bd);position:sticky;top:0;background:var(--bg-2);z-index:1}\n        .admit-card{padding:12px 16px;border-bottom:1px solid var(--bd);cursor:pointer;transition:all 100ms;position:relative}\n        .admit-card:hover{background:var(--bg-1)}\n        .admit-status{display:inline-block;font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;background:var(--acc-bg);color:var(--acc);border:1px solid rgba(37,99,235,.15);margin-top:4px}\n        .admit-status.urg{background:var(--red-bg);color:var(--red);border-color:var(--red-bd)}\n        .admit-status-sel{padding:3px 6px;font-family:var(--font);font-size:11px;font-weight:600;border:1px solid var(--bd);border-radius:4px;background:var(--bg-1);color:var(--t1);cursor:pointer;margin-top:4px}\n        .pm-edit-panel{padding:16px;border-bottom:1px solid var(--bd);background:var(--bg-2);flex-shrink:0;display:none}\n        .pm-edit-panel.open{display:block}\n        .pm-edit-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}\n        .pm-edit-field{display:flex;flex-direction:column;gap:2px}\n        .pm-edit-field label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3)}\n        .pm-edit-field input,.pm-edit-field select{padding:6px 8px;font-family:var(--font);font-size:12px;border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);background:var(--bg-1)}\n        .pm-edit-field input:focus,.pm-edit-field select:focus{outline:none;border-color:var(--acc)}\n        .pm-edit-btns{display:flex;gap:6px;justify-content:flex-end;margin-top:10px}\n        .pm-toggle-edit{background:none;border:none;font-size:11px;font-weight:600;color:var(--acc);cursor:pointer;padding:0}\n        .pm-toggle-edit:hover{text-decoration:underline}\n        .admit-card.active{background:var(--bg-1);border-left:3px solid var(--acc)}\n        .admit-dates{font-size:13px;font-weight:600;color:var(--t1)}\n        .admit-meta{font-size:11px;color:var(--t3);margin-top:3px}\n        .admit-notes-count{font-size:10px;color:var(--t3);margin-top:4px}\n        .pm-notes{flex:1;display:flex;flex-direction:column;overflow:hidden}\n        .pm-notes-header{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);padding:12px 16px;border-bottom:1px solid var(--bd);background:var(--bg-2);flex-shrink:0;display:flex;align-items:center;justify-content:space-between}\n        .pm-notes-list{flex:1;overflow-y:auto;padding:12px}\n        .pm-note-input{flex-shrink:0;border-top:1px solid var(--bd);padding:12px 16px;background:var(--bg-2);display:flex;gap:8px}\n        .pm-note-input textarea{flex:1;padding:8px 10px;font-family:var(--font);font-size:13px;border:1px solid var(--bd);border-radius:var(--r);resize:none;height:60px;color:var(--t1)}\n        .pm-note-input textarea:focus{outline:none;border-color:var(--acc)}\n        .note-card{border:1px solid var(--bd);border-radius:var(--r);margin-bottom:6px;overflow:hidden}\n        .note-card:hover{border-color:rgba(37,99,235,.2)}\n        .note-head{display:flex;align-items:center;justify-content:space-between;padding:6px 10px;background:var(--bg-2);font-size:11px;color:var(--t3);border-bottom:1px solid var(--bd)}\n        .note-text{padding:8px 10px;font-size:13px;color:var(--t1);line-height:1.5;white-space:pre-wrap}\n        .note-btn{background:none;border:none;cursor:pointer;font-size:13px;color:var(--t3);padding:1px 3px}.note-btn:hover{color:var(--acc)}\n        .note-del:hover{color:var(--red)}\n        .notes-empty{text-align:center;padding:30px;color:var(--t3);font-size:13px}\n        /* CALENDAR DAY MODAL */\n        .cdm{max-width:560px;height:550px;display:flex;flex-direction:column}\n        .cd-cards{flex:1;overflow-y:auto;padding:14px;display:flex;flex-direction:column;gap:8px}\n        .cd-card{background:var(--bg-2);border:1px solid var(--bd);border-radius:var(--r);padding:12px 14px;cursor:pointer;transition:all 120ms;border-left:3px solid transparent}\n        .cd-card:hover{border-left-color:var(--acc);box-shadow:0 2px 8px rgba(0,0,0,.06)}\n        /* CALENDAR */\n        .calendar-view{display:none;padding:20px 24px}.calendar-view.visible{display:block}\n        .cal-c{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--rl);overflow:hidden;box-shadow:var(--sh)}\n        .cal-hdr{display:flex;align-items:center;justify-content:space-between;padding:14px 18px;border-bottom:1px solid var(--bd)}\n        .cal-title{font-size:17px;font-weight:700}\n        .cal-nav{display:flex;gap:4px}\n        .cal-nb{width:30px;height:30px;border-radius:var(--r);border:1px solid var(--bd);background:var(--bg-1);cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center}\n        .cal-nb:hover{background:var(--bg-2);border-color:var(--acc)}\n        .cal-tb{padding:5px 12px;border-radius:var(--r);border:1px solid var(--bd);background:var(--bg-1);cursor:pointer;font-family:var(--font);font-size:11px;font-weight:600;color:var(--acc)}\n        .cal-tb:hover{background:var(--acc-bg)}\n        .cal-grid{display:grid;grid-template-columns:repeat(7,1fr)}\n        .cal-dh{padding:8px;text-align:center;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);background:var(--bg-2);border-bottom:1px solid var(--bd)}\n        .cal-d{position:relative;min-height:90px;padding:6px;border-bottom:1px solid #f0f1f4;border-right:1px solid #f0f1f4;cursor:pointer;transition:background 120ms;background:var(--bg-1)}\n        .cal-d:hover{background:var(--bg-2)}.cal-d.out{background:var(--bg-2);opacity:.35;cursor:default}\n        .cal-d.today{background:var(--acc-bg)}.cal-d.sel{background:var(--acc-bg);box-shadow:inset 0 0 0 2px var(--acc)}\n        .cal-dn{font-size:12px;font-weight:600;color:var(--t1);margin-bottom:3px}\n        .cal-badge{display:inline-block;font-size:9px;font-weight:700;padding:1px 5px;border-radius:10px;margin-bottom:2px}\n        .cal-badge.n{background:var(--acc-bg);color:var(--acc)}.cal-badge.u{background:var(--red-bg);color:var(--red)}\n        .cal-pv{font-size:9px;color:var(--t2);line-height:1.2;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n        .cal-more{font-size:9px;color:var(--acc);font-weight:600}\n        /* MAPPING */\n        .map-panel{padding:28px;max-width:640px;margin:0 auto}\n        .map-panel h3{font-size:18px;font-weight:700;margin-bottom:16px}\n        .fi{display:flex;flex-direction:column;gap:4px;margin-bottom:10px}\n        .fi label{font-size:10px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.05em}\n        .fi select,.fi input{padding:7px 10px;font-family:var(--font);font-size:13px;border:1px solid var(--bd);border-radius:var(--r);color:var(--t1)}\n        .team-sheet-list{margin-bottom:14px}\n        .team-sheet-row{display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--bd)}\n        .team-sheet-row input[type=\"checkbox\"]{width:16px;height:16px;accent-color:var(--acc)}\n        .team-sheet-row span{font-size:13px;color:var(--t1);flex:1}\n        /* TOAST */\n        #toasts{position:fixed;bottom:20px;right:20px;z-index:9999;display:flex;flex-direction:column;gap:8px}\n        .toast{padding:10px 18px;border-radius:var(--r);font-size:13px;font-weight:600;box-shadow:0 4px 12px rgba(0,0,0,.15);animation:tIn .2s;transition:opacity .2s}\n        .toast-success{background:#065f46;color:#ecfdf5}.toast-danger{background:#991b1b;color:#fef2f2}.toast-info{background:#1e40af;color:#eff6ff}\n        .toast.out{opacity:0}\n        @keyframes tIn{from{transform:translateY(8px);opacity:0}to{transform:none;opacity:1}}\n    </style>\n</head>\n<body>\n<div id=\"setup\">\n    <h1>Team<span class=\"ac\">Manager</span></h1>\n    <p style=\"color:var(--t3);font-size:14px;margin-bottom:4px\">Shared Excel workbook for your care team</p>\n    <div class=\"setup-card\" onclick=\"App.openFile()\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--acc)\" stroke-width=\"1.5\" style=\"width:42px;height:42px;margin-bottom:14px\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M8 7h3l2 5-2 5H8\"/><path d=\"M16 7h-3l-2 5 2 5h3\"/></svg>\n        <div style=\"font-size:17px;font-weight:700;color:var(--t1);margin-bottom:6px\">Open Excel File</div>\n        <p style=\"font-size:12px;color:var(--t3);margin:0\">Each sheet = a team. Notes in a dedicated sheet.</p>\n    </div>\n    <div class=\"setup-err\" id=\"setupErr\"></div>\n</div>\n\n<div id=\"app\">\n    <div class=\"toolbar\">\n        <h2>Team<span class=\"ac\">Manager</span></h2>\n        <div class=\"view-toggle\">\n            <button class=\"vtb active\" data-view=\"table\" onclick=\"App.setView('table')\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg>Patients</button>\n            <button class=\"vtb\" data-view=\"calendar\" onclick=\"App.setView('calendar')\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\"/><line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\"/><line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\"/></svg>Calendar</button>\n        </div>\n        <div class=\"search-wrap\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><line x1=\"21\" y1=\"21\" x2=\"16.65\" y2=\"16.65\"/></svg>\n            <input class=\"search-input\" id=\"searchInput\" placeholder=\"Search patients...\" oninput=\"App.onSearch(this.value)\" style=\"padding-right:28px\">\n            <button class=\"search-clear\" onclick=\"App.clearSearch()\">&times;</button>\n        </div>\n        <span class=\"fb\" id=\"badgeFile\"></span>\n        <button class=\"btn btn-sm\" onclick=\"App.refresh()\">Refresh</button>\n        <button class=\"btn btn-sm btn-p\" onclick=\"App.startImportCSV()\">Import CSV</button>\n        <button class=\"btn btn-sm\" onclick=\"App.showMap()\">Remap</button>\n    </div>\n    <div class=\"filter-bar\" id=\"filterBar\">\n        <div class=\"fg-item\"><label>Team</label><div class=\"ms-wrap\" data-key=\"fTeam\"><button class=\"ms-btn\" onclick=\"App.toggleMS('fTeam')\">All</button><div class=\"ms-drop\" id=\"fTeam_drop\"></div></div></div>\n        <div class=\"fg-item\"><label>CM</label><div class=\"ms-wrap\" data-key=\"fCM\"><button class=\"ms-btn\" onclick=\"App.toggleMS('fCM')\">All</button><div class=\"ms-drop\" id=\"fCM_drop\"></div></div></div>\n        <div class=\"fg-item\"><label>Status</label><div class=\"ms-wrap\" data-key=\"fCT\"><button class=\"ms-btn\" onclick=\"App.toggleMS('fCT')\">All</button><div class=\"ms-drop\" id=\"fCT_drop\"></div></div></div>\n        <div class=\"fg-item\"><label>SNP</label><div class=\"ms-wrap\" data-key=\"fSNP\"><button class=\"ms-btn\" onclick=\"App.toggleMS('fSNP')\">All</button><div class=\"ms-drop\" id=\"fSNP_drop\"></div></div></div>\n        <div class=\"fg-item\"><label>PCP</label><div class=\"ms-wrap\" data-key=\"fPCP\"><button class=\"ms-btn\" onclick=\"App.toggleMS('fPCP')\">All</button><div class=\"ms-drop\" id=\"fPCP_drop\"></div></div></div>\n        <div class=\"fg-item\"><label>D/C From</label><input type=\"date\" id=\"fFrom\" onchange=\"App.render()\"></div>\n        <div class=\"fg-item\"><label>D/C To</label><input type=\"date\" id=\"fTo\" onchange=\"App.render()\"></div>\n        <button class=\"btn btn-sm\" onclick=\"App.clearFilters()\">Clear</button>\n    </div>\n    <div id=\"cardView\">\n        <div class=\"stats-bar\" id=\"statsBar\"></div>\n        <div class=\"cards\" id=\"cardGrid\"></div>\n        <div class=\"empty-state\" id=\"emptyState\" style=\"display:none\"><p>No patients match your filters.</p></div>\n    </div>\n    <div id=\"mapPanel\" style=\"display:none\">\n        <div class=\"map-panel\">\n            <h3>Setup Teams &amp; Columns</h3>\n            <p style=\"font-size:13px;color:var(--t3);margin-bottom:16px\">Select sheets to load as teams. Each sheet uses the same column layout.</p>\n            <div class=\"team-sheet-list\" id=\"teamSheetList\"></div>\n            <h3 style=\"font-size:15px;margin-top:20px\">Column Mapping</h3>\n            <div id=\"xlMappings\"></div>\n            <div class=\"fi\" style=\"margin-top:16px\"><label>Notes Sheet</label><select id=\"xlNoteSheet\"></select></div>\n            <p style=\"font-size:11px;color:var(--t3);margin-bottom:16px\">Notes stored as: Member ID, Admission#, Timestamp, Note</p>\n            <button class=\"btn btn-p\" onclick=\"App.applyMap()\" style=\"padding:10px 28px\">Load Patients</button>\n        </div>\n    </div>\n    <div class=\"calendar-view\" id=\"calView\">\n        <div class=\"cal-c\"><div class=\"cal-hdr\"><div class=\"cal-nav\"><button class=\"cal-nb\" onclick=\"App.calPrev()\">&lsaquo;</button><button class=\"cal-nb\" onclick=\"App.calNext()\">&rsaquo;</button></div><div class=\"cal-title\" id=\"calTitle\"></div><button class=\"cal-tb\" onclick=\"App.calToday()\">Today</button></div><div class=\"cal-grid\" id=\"calGrid\"></div></div>\n    </div>\n</div>\n\n<!-- IMPORT CSV MODAL -->\n<div class=\"mo\" id=\"importModal\" onclick=\"if(event.target===this)App.hideImport()\">\n    <div class=\"modal\" style=\"max-width:600px;max-height:85vh;display:flex;flex-direction:column;overflow:hidden\">\n        <div class=\"mh\"><h2>Import Admissions CSV</h2><button class=\"mx\" onclick=\"App.hideImport()\">&times;</button></div>\n        <div style=\"flex:1;overflow-y:auto;padding:20px\">\n            <p style=\"color:var(--t2);font-size:13px;margin-bottom:14px\">Map CSV columns. New admissions (by Auth Number) get status \"Added Today\".</p>\n            <div class=\"fi\"><label>Import to Team</label><select id=\"impTeam\"></select></div>\n            <div id=\"impMappings\" style=\"margin-top:12px\"></div>\n            <div style=\"border:1px solid var(--bd);border-radius:var(--r);padding:14px;margin-top:14px;background:var(--bg-2)\">\n                <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:8px\">\n                    <label style=\"font-size:10px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.05em\">Filters</label>\n                    <button class=\"btn btn-sm\" onclick=\"App.addImpFilter()\">+ Add Filter</button>\n                </div>\n                <div id=\"impFilters\"><div style=\"color:var(--t3);font-size:12px\">No filters — all rows imported</div></div>\n            </div>\n            <div id=\"impPreview\" style=\"margin-top:12px;font-size:12px;color:var(--t3)\"></div>\n        </div>\n        <div class=\"mf\"><button class=\"btn\" onclick=\"App.hideImport()\">Cancel</button><button class=\"btn btn-p\" onclick=\"App.runImport()\">Import</button></div>\n    </div>\n</div>\n\n<!-- PATIENT MODAL -->\n<div class=\"mo\" id=\"patientModal\" onclick=\"if(event.target===this)App.closePM()\">\n    <div class=\"modal pm\">\n        <div class=\"pm-header\" id=\"pmHeader\"></div>\n        <div class=\"pm-body\">\n            <div class=\"pm-admissions\">\n                <div class=\"pm-admit-hdr\">Admissions</div>\n                <div id=\"pmAdmitList\"></div>\n            </div>\n            <div class=\"pm-notes\">\n                <div class=\"pm-notes-header\"><span id=\"pmNotesTitle\">Notes</span><span id=\"pmNotesCount\" style=\"font-size:11px;color:var(--t3);font-weight:400\"></span><button class=\"pm-toggle-edit\" id=\"pmEditToggle\" onclick=\"App.toggleEdit()\">Edit Fields</button></div>\n                <div class=\"pm-edit-panel\" id=\"pmEditPanel\">\n                    <div class=\"pm-edit-grid\" id=\"pmEditGrid\"></div>\n                    <div class=\"pm-edit-btns\"><button class=\"btn btn-sm btn-p\" onclick=\"App.saveEdit()\">Save Changes</button></div>\n                </div>\n                <div class=\"pm-notes-list\" id=\"pmNotesList\"></div>\n                <div class=\"pm-note-input\"><textarea id=\"pmNoteInput\" placeholder=\"Add a note...\"></textarea><button class=\"btn btn-p btn-sm\" onclick=\"App.addNote()\">Add</button></div>\n            </div>\n        </div>\n    </div>\n</div>\n<!-- CAL DAY MODAL -->\n<div class=\"mo\" id=\"calDayModal\" onclick=\"if(event.target===this)App.closeCD()\">\n    <div class=\"modal cdm\"><div class=\"mh\"><h2 id=\"cdTitle\"></h2><button class=\"mx\" onclick=\"App.closeCD()\">&times;</button></div><div id=\"cdList\" class=\"cd-cards\"></div></div>\n</div>\n<div id=\"toasts\"></div>\n\n<script src=\"https://cdn.sheetjs.com/xlsx-0.20.3/package/dist/xlsx.full.min.js\"></script>\n<script>\nvar CALL_TYPES=[];\n\nvar App={\n    handle:null,wb:null,patients:{},admissions:[],notes:[],nextNid:1,\n    query:'',currentView:'table',calYear:new Date().getFullYear(),calMonth:new Date().getMonth(),calSel:null,\n    pmPatient:null,pmAdmitIdx:0,_retCal:false,\n\n    fields:[\n        {key:'authNumber',label:'Auth Number',hints:['auth','authorization','auth number','auth#','auth no']},\n        {key:'memberId',label:'Member ID',hints:['member id','memberid','id','hicn']},\n        {key:'lastName',label:'Last Name',hints:['last name','lastname','last']},\n        {key:'firstName',label:'First Name',hints:['first name','firstname','first']},\n        {key:'metalTier',label:'Metal Tier',hints:['metal tier','tier','metal','plan tier','plan']},\n        {key:'snpFlag',label:'SNP Flag',hints:['snp','snp flag','flag']},\n        {key:'pcp',label:'PCP',hints:['pcp','primary care','physician']},\n        {key:'dob',label:'DOB',hints:['dob','date of birth','birth']},\n        {key:'callType',label:'Status',hints:['status','call type','calltype']},\n        {key:'cm',label:'CM',hints:['cm','care manager','case manager']},\n        {key:'admitDate',label:'Admit Date',hints:['admit date','admit','admission']},\n        {key:'dcDate',label:'D/C Date',hints:['d/c date','dc date','discharge']},\n        {key:'tocApptDate',label:'TOC Appt',hints:['toc appt','appointment','toc date']},\n        {key:'tocKept',label:'TOC Kept',hints:['toc kept','kept','kept status','appt status']}\n    ],\n\n    getMap:function(){try{return JSON.parse(localStorage.getItem('tm2Map')||'{}')}catch(e){return{}}},\n    saveMap:function(m){localStorage.setItem('tm2Map',JSON.stringify(m))},\n    esc:function(s){if(s==null)return'';var d=document.createElement('div');d.textContent=String(s);return d.innerHTML},\n    fmtTime:function(iso){try{var d=new Date(iso);return d.toLocaleDateString('en-US',{month:'short',day:'numeric'})+' '+d.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'})}catch(e){return iso}},\n    fmtDate:function(s){if(!s)return'';var p=s.split('-');if(p.length!==3)return s;return['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][+p[1]-1]+' '+parseInt(p[2])+', '+p[0]},\n    parseDate:function(v){if(!v)return'';if(typeof v==='number'){var d=new Date((v-25569)*86400000);return d.toISOString().split('T')[0]}var s=String(v).trim();if(/^\\d{4}-\\d{2}-\\d{2}/.test(s))return s.substring(0,10);var d=new Date(s);return isNaN(d)?s:d.toISOString().split('T')[0]},\n    copy:function(t){navigator.clipboard.writeText(t).then(function(){App.toast('Copied','success')})},\n    toast:function(msg,type){var el=document.createElement('div');el.className='toast toast-'+(type||'info');el.textContent=msg;document.getElementById('toasts').appendChild(el);setTimeout(function(){el.classList.add('out');setTimeout(function(){el.remove()},200)},2500)},\n\n    openFile:function(){\n        var self=this;\n        window.showOpenFilePicker({types:[{description:'Excel',accept:{'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet':['.xlsx','.xls']}}]}).then(function(h){\n            self.handle=h[0];return self.handle.getFile();\n        }).then(function(f){self.fileName=f.name;return f.arrayBuffer()}).then(function(buf){\n            self.wb=XLSX.read(buf);\n            document.getElementById('setup').style.display='none';\n            document.getElementById('app').style.display='block';\n            document.getElementById('badgeFile').textContent=self.fileName;\n            var saved=self.getMap();\n            if(saved.teams&&saved.teams.length)self.applyMap();else self.showMap();\n        }).catch(function(e){if(e.name!=='AbortError')self.toast(e.message,'danger')});\n    },\n    refresh:function(){if(!this.handle)return;var self=this;this.handle.getFile().then(function(f){return f.arrayBuffer()}).then(function(buf){self.wb=XLSX.read(buf);self.loadData();self.toast('Refreshed','success')})},\n\n    showMap:function(){\n        document.getElementById('cardView').style.display='none';document.getElementById('calView').classList.remove('visible');\n        document.getElementById('filterBar').style.display='none';document.getElementById('mapPanel').style.display='';\n        var names=this.wb.SheetNames,saved=this.getMap(),self=this;\n        var savedTeams=saved.teams||[];\n        document.getElementById('teamSheetList').innerHTML=names.map(function(n,i){\n            var checked=savedTeams.some(function(t){return t.sheet===i})||(!savedTeams.length&&n.toLowerCase()!=='notes');\n            return '<div class=\"team-sheet-row\"><input type=\"checkbox\" data-idx=\"'+i+'\"'+(checked?' checked':'')+'><span>'+self.esc(n)+'</span></div>';\n        }).join('');\n        // Column mapping from first checked sheet\n        var firstSheet=0;document.querySelectorAll('#teamSheetList input:checked').forEach(function(cb,i){if(i===0)firstSheet=parseInt(cb.dataset.idx)});\n        this.buildColMap(firstSheet,saved);\n        var nSel=document.getElementById('xlNoteSheet');\n        nSel.innerHTML='<option value=\"__new__\">+ Create \"Notes\" sheet</option>'+names.map(function(n,i){return '<option value=\"'+i+'\"'+((saved.noteSheet===i||(n.toLowerCase()==='notes'&&saved.noteSheet==null))?' selected':'')+'>'+n+'</option>'}).join('');\n    },\n    buildColMap:function(si,saved){\n        var ws=this.wb.Sheets[this.wb.SheetNames[si]];\n        var data=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});\n        var cols=data[0]?data[0].map(function(h){return String(h).trim()}):[];\n        var self=this;\n        document.getElementById('xlMappings').innerHTML=this.fields.map(function(f){\n            var best=-1;\n            if(saved.cols&&saved.cols[f.key]!=null)best=saved.cols[f.key];\n            else cols.forEach(function(c,i){var cl=c.toLowerCase();if(best===-1&&f.hints.some(function(h){return cl.indexOf(h)>-1}))best=i});\n            var opts='<option value=\"-1\">-- Skip --</option>'+cols.map(function(c,i){return '<option value=\"'+i+'\"'+(i===best?' selected':'')+'>'+self.esc(c)+'</option>'}).join('');\n            return '<div class=\"fi\"><label>'+f.label+'</label><select id=\"xlM_'+f.key+'\">'+opts+'</select></div>';\n        }).join('');\n    },\n    applyMap:function(){\n        var saved=this.getMap(),map={};\n        var panel=document.getElementById('mapPanel');\n        if(panel.style.display!=='none'){\n            map.teams=[];\n            document.querySelectorAll('#teamSheetList input:checked').forEach(function(cb){\n                var idx=parseInt(cb.dataset.idx);\n                map.teams.push({sheet:idx,name:App.wb.SheetNames[idx]});\n            });\n            if(!map.teams.length){this.toast('Select at least one team sheet','danger');return}\n            map.cols={};var self=this;\n            this.fields.forEach(function(f){map.cols[f.key]=parseInt(document.getElementById('xlM_'+f.key).value)});\n            var nv=document.getElementById('xlNoteSheet').value;\n            map.noteSheet=nv==='__new__'?-1:parseInt(nv);\n            this.saveMap(map);\n        }else{map=saved}\n        this.map=map;\n        if(map.noteSheet===-1||map.noteSheet==null){\n            var ni=this.wb.SheetNames.indexOf('Notes');\n            if(ni===-1){XLSX.utils.book_append_sheet(this.wb,XLSX.utils.aoa_to_sheet([['Member ID','Admission','Timestamp','Note']]),'Notes');map.noteSheet=this.wb.SheetNames.indexOf('Notes');this.saveMap(map);this.saveFile()}\n            else{map.noteSheet=ni;this.saveMap(map)}\n        }\n        panel.style.display='none';document.getElementById('filterBar').style.display='';document.getElementById('cardView').style.display='';\n        this.loadData();\n    },\n\n    loadData:function(){\n        var map=this.map||this.getMap();if(!this.wb||!map.teams)return;\n        var c=map.cols,self=this;\n        this.admissions=[];\n        map.teams.forEach(function(team){\n            var ws=self.wb.Sheets[self.wb.SheetNames[team.sheet]];\n            if(!ws)return;\n            var rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});\n            rows.slice(1).forEach(function(r,ri){\n                var mid=c.memberId>=0?String(r[c.memberId]||'').trim():'';if(!mid)return;\n                var last=c.lastName>=0?String(r[c.lastName]||'').trim():'';\n                var first=c.firstName>=0?String(r[c.firstName]||'').trim():'';\n                var auth=c.authNumber>=0?String(r[c.authNumber]||'').trim():'';\n                self.admissions.push({\n                    authNumber:auth,\n                    memberId:mid,name:last&&first?last+', '+first:(last||first),firstName:first,lastName:last,\n                    metalTier:c.metalTier>=0?String(r[c.metalTier]||'').trim():'',\n                    snpFlag:c.snpFlag>=0?String(r[c.snpFlag]||'').trim():'',\n                    pcp:c.pcp>=0?String(r[c.pcp]||'').trim():'',\n                    dob:c.dob>=0?self.parseDate(r[c.dob]):'',\n                    callType:c.callType>=0?String(r[c.callType]||'').trim():'',\n                    cm:c.cm>=0?String(r[c.cm]||'').trim():'',\n                    admitDate:c.admitDate>=0?self.parseDate(r[c.admitDate]):'',\n                    dcDate:c.dcDate>=0?self.parseDate(r[c.dcDate]):'',\n                    tocApptDate:c.tocApptDate>=0?self.parseDate(r[c.tocApptDate]):'',\n                    tocKept:c.tocKept>=0?String(r[c.tocKept]||'').trim():'',\n                    team:team.name,teamSheet:team.sheet,xlRow:ri+1\n                });\n            });\n        });\n        // Group by memberId → patients (use latest admission for demographics)\n        this.patients={};\n        this.admissions.forEach(function(a){\n            if(!self.patients[a.memberId]){\n                self.patients[a.memberId]={memberId:a.memberId,name:a.name,firstName:a.firstName,lastName:a.lastName,\n                    snpFlag:a.snpFlag,pcp:a.pcp,dob:a.dob,metalTier:a.metalTier,cm:a.cm,admissions:[]};\n            }\n            var p=self.patients[a.memberId];\n            // Update patient demographics from most recent admission\n            if(!p.admissions.length||(a.admitDate||'')>=(p._latestAdmit||'')){\n                if(a.name)p.name=a.name;if(a.firstName)p.firstName=a.firstName;if(a.lastName)p.lastName=a.lastName;\n                if(a.pcp)p.pcp=a.pcp;if(a.dob)p.dob=a.dob;if(a.snpFlag)p.snpFlag=a.snpFlag;\n                if(a.metalTier)p.metalTier=a.metalTier;if(a.cm)p.cm=a.cm;\n                p._latestAdmit=a.admitDate||'';\n            }\n            p.admissions.push(a);\n        });\n        // Sync Members sheet\n        this.syncMembersSheet();\n        // Notes\n        this.notes=[];\n        if(map.noteSheet>=0){\n            var nws=this.wb.Sheets[this.wb.SheetNames[map.noteSheet]];\n            if(nws){var nr=XLSX.utils.sheet_to_json(nws,{header:1,defval:''});\n                nr.slice(1).forEach(function(r,i){var mid=String(r[0]||'').trim(),auth=String(r[1]||'').trim(),ts=String(r[2]||'').trim(),n=String(r[3]||'').trim();if(mid&&n)self.notes.push({id:String(i+1),memberId:mid,admission:auth,ts:ts,note:n})});\n                var mx=0;self.notes.forEach(function(n){var v=parseInt(n.id);if(!isNaN(v)&&v>mx)mx=v});self.nextNid=mx+1;\n            }\n        }\n        // Build status types from actual data\n        var ctSet={};this.admissions.forEach(function(a){if(a.callType)ctSet[a.callType]=true});\n        CALL_TYPES=Object.keys(ctSet).sort();\n        this.populateFilters();this.render();\n    },\n\n    saveFile:function(){if(!this.handle||!this.wb)return;var buf=XLSX.write(this.wb,{bookType:'xlsx',type:'array'});this.handle.createWritable().then(function(w){w.write(new Blob([buf])).then(function(){w.close()})})},\n    writeNotes:function(){var map=this.map||this.getMap();if(map.noteSheet<0||!this.wb)return;var aoa=[['Member ID','Auth Number','Timestamp','Note']];this.notes.forEach(function(n){aoa.push([n.memberId,n.admission||'',n.ts,n.note])});this.wb.Sheets[this.wb.SheetNames[map.noteSheet]]=XLSX.utils.aoa_to_sheet(aoa);this.saveFile()},\n    syncMembersSheet:function(){\n        if(!this.wb)return;\n        var mi=this.wb.SheetNames.indexOf('Members');\n        var aoa=[['Member ID','Last Name','First Name','Metal Tier','SNP Flag','PCP','DOB','CM']];\n        var self=this;\n        Object.keys(this.patients).sort().forEach(function(mid){\n            var p=self.patients[mid];\n            aoa.push([p.memberId,p.lastName||'',p.firstName||'',p.metalTier||'',p.snpFlag||'',p.pcp||'',p.dob||'',p.cm||'']);\n        });\n        var ws=XLSX.utils.aoa_to_sheet(aoa);\n        if(mi===-1){XLSX.utils.book_append_sheet(this.wb,ws,'Members')}\n        else{this.wb.Sheets['Members']=ws}\n        this.saveFile();\n    },\n\n    // FILTERS (multi-select)\n    msState:{fTeam:{},fCM:{},fCT:{},fSNP:{},fPCP:{}},\n    populateFilters:function(){\n        var teams={},cms={},cts={},snps={},pcps={};\n        this.admissions.forEach(function(a){\n            if(a.team)teams[a.team]=true;if(a.cm)cms[a.cm]=true;\n            if(a.callType)cts[a.callType]=true;if(a.snpFlag)snps[a.snpFlag]=true;if(a.pcp)pcps[a.pcp]=true;\n        });\n        this.buildMS('fTeam',teams);this.buildMS('fCM',cms);this.buildMS('fCT',cts);this.buildMS('fSNP',snps);this.buildMS('fPCP',pcps);\n    },\n    buildMS:function(key,vals){\n        var sorted=Object.keys(vals).sort(),self=this,state=this.msState[key]||{};\n        var drop=document.getElementById(key+'_drop');\n        drop.innerHTML=sorted.map(function(v){\n            var checked=state[v]?' checked':'';\n            return '<label><input type=\"checkbox\" data-key=\"'+key+'\" data-val=\"'+self.esc(v)+'\"'+checked+' onchange=\"App.msChanged(\\''+key+'\\',this)\">'+self.esc(v)+'</label>';\n        }).join('');\n        this.updateMSBtn(key);\n    },\n    msChanged:function(key,cb){\n        if(!this.msState[key])this.msState[key]={};\n        if(cb.checked)this.msState[key][cb.dataset.val]=true;\n        else delete this.msState[key][cb.dataset.val];\n        this.updateMSBtn(key);this.render();\n    },\n    updateMSBtn:function(key){\n        var state=this.msState[key]||{};\n        var keys=Object.keys(state);\n        var btn=document.querySelector('.ms-wrap[data-key=\"'+key+'\"] .ms-btn');\n        if(!btn)return;\n        if(!keys.length)btn.textContent='All';\n        else if(keys.length===1)btn.textContent=keys[0];\n        else btn.textContent=keys.length+' selected';\n    },\n    toggleMS:function(key){\n        var drop=document.getElementById(key+'_drop');\n        var wasOpen=drop.classList.contains('open');\n        document.querySelectorAll('.ms-drop.open').forEach(function(d){d.classList.remove('open')});\n        if(!wasOpen){\n            drop.classList.add('open');\n            setTimeout(function(){document.addEventListener('click',function close(e){if(!drop.contains(e.target)&&!e.target.classList.contains('ms-btn')){drop.classList.remove('open');document.removeEventListener('click',close)}})},0);\n        }\n    },\n    getMS:function(key){var s=this.msState[key]||{};var k=Object.keys(s);return k.length?s:null},\n    clearFilters:function(){this.msState={fTeam:{},fCM:{},fCT:{},fSNP:{},fPCP:{}};this.populateFilters();document.getElementById('fFrom').value='';document.getElementById('fTo').value='';this.render()},\n\n    getFilteredPatients:function(){\n        var team=this.getMS('fTeam'),cm=this.getMS('fCM');\n        var ct=this.getMS('fCT'),snp=this.getMS('fSNP');\n        var pcp=this.getMS('fPCP');\n        var df=document.getElementById('fFrom').value,dt=document.getElementById('fTo').value;\n        var q=this.query.toLowerCase();\n        var result=[],self=this;\n        Object.keys(this.patients).forEach(function(mid){\n            var p=self.patients[mid];\n            // Filter admissions\n            var admits=p.admissions.filter(function(a){\n                if(team&&!team[a.team])return false;\n                if(cm&&!cm[a.cm])return false;\n                if(ct&&!ct[a.callType])return false;\n                if(df&&(a.dcDate||'')<df)return false;\n                if(dt&&(a.dcDate||'')>dt)return false;\n                return true;\n            });\n            if(!admits.length)return;\n            if(snp&&!snp[p.snpFlag])return;\n            if(pcp&&!pcp[p.pcp])return;\n            if(q&&p.name.toLowerCase().indexOf(q)===-1&&mid.toLowerCase().indexOf(q)===-1&&(p.pcp||'').toLowerCase().indexOf(q)===-1)return;\n            result.push({patient:p,admissions:admits});\n        });\n        result.sort(function(a,b){return a.patient.name<b.patient.name?-1:a.patient.name>b.patient.name?1:0});\n        return result;\n    },\n\n    render:function(){\n        var list=this.getFilteredPatients(),self=this;\n        var totalAdmits=0;list.forEach(function(r){totalAdmits+=r.admissions.length});\n        document.getElementById('statsBar').innerHTML='<div class=\"stat\"><b>'+list.length+'</b> patients</div><div class=\"stat\"><b>'+totalAdmits+'</b> admissions</div><div class=\"stat\"><b>'+Object.keys(this.patients).length+'</b> total in workbook</div>';\n        if(!list.length){document.getElementById('cardGrid').innerHTML='';document.getElementById('emptyState').style.display='';return}\n        document.getElementById('emptyState').style.display='none';\n        document.getElementById('cardGrid').innerHTML=list.map(function(r){\n            var p=r.patient,admits=r.admissions;\n            var latest=admits[0];admits.forEach(function(a){if((a.dcDate||'')>(latest.dcDate||''))latest=a});\n            var nc=self.notes.filter(function(n){return n.memberId===p.memberId}).length;\n            var teams={};admits.forEach(function(a){if(a.team)teams[a.team]=true});\n            var teamBadges=Object.keys(teams).map(function(t){return '<span class=\"p-team\">'+self.esc(t)+'</span>'}).join(' ');\n            var statusCls=latest.callType==='Urgent'?'p-status-urg':(latest.callType==='Readmitted'?'p-status-warn':'p-status-ok');\n            var keptCls='p-kept-none',keptText=latest.tocKept||'Set';\n            if(latest.tocKept==='Kept')keptCls='p-kept-kept';\n            else if(latest.tocKept==='No Show')keptCls='p-kept-noshow';\n            else if(latest.tocKept==='Cancelled')keptCls='p-kept-cancelled';\n            else if(latest.tocKept==='Expected')keptCls='p-kept-expected';\n            var ri=self.admissions.indexOf(latest);\n            return '<div class=\"p-card\" data-mid=\"'+self.esc(p.memberId)+'\">'\n                +'<div class=\"p-card-header\">'\n                +'<div class=\"p-card-name\">'+self.esc(p.name)+'</div>'\n                +'<div class=\"p-card-id\">'+self.esc(p.memberId)+' <button class=\"copy-id\" onclick=\"event.stopPropagation();App.copy(\\''+self.esc(p.memberId)+'\\')\">&#9112;</button>'\n                +(p.metalTier?' <span class=\"tier-badge tier-'+p.metalTier.toLowerCase()+'\">'+self.esc(p.metalTier)+'</span>':'')\n                +'</div>'\n                +'</div>'\n                +'<div class=\"p-card-admission\">'\n                +'<div class=\"p-card-dates\">'\n                +'<div class=\"p-date-block\"><div class=\"p-date-label\">Admit</div><div class=\"p-date-val\">'+(latest.admitDate?self.fmtDate(latest.admitDate):'—')+'</div></div>'\n                +'<div class=\"p-date-arrow\">&rarr;</div>'\n                +'<div class=\"p-date-block\"><div class=\"p-date-label\">D/C</div><div class=\"p-date-val\">'+(latest.dcDate?self.fmtDate(latest.dcDate):'—')+'</div></div>'\n                +'</div>'\n                +'<div class=\"p-card-status '+statusCls+'\" data-ri=\"'+ri+'\" onclick=\"event.stopPropagation();App.showStatusPop(this,'+ri+')\">'+self.esc(latest.callType||'—')+'</div>'\n                +'</div>'\n                +'<div class=\"p-toc-row\">'\n                +'<div class=\"p-toc-date\"><span class=\"p-toc-date-label\">TOC Appt</span> <span class=\"p-toc-date-val\" data-ri=\"'+ri+'\" onclick=\"event.stopPropagation();App.showDatePop(this,'+ri+')\">'+(latest.tocApptDate?self.fmtDate(latest.tocApptDate):'Set date')+'</span></div>'\n                +'<span class=\"p-toc-kept '+keptCls+'\" data-ri=\"'+ri+'\" onclick=\"event.stopPropagation();App.showKeptPop(this,'+ri+')\">'+self.esc(keptText)+'</span>'\n                +'</div>'\n                +'<div class=\"p-card-details\">'\n                +(latest.cm?'<div class=\"p-field\"><span class=\"p-field-l\">CM</span><span class=\"p-field-v\">'+self.esc(latest.cm)+'</span></div>':'')\n                +(p.pcp?'<div class=\"p-field\"><span class=\"p-field-l\">PCP</span><span class=\"p-field-v\">'+self.esc(p.pcp)+'</span></div>':'')\n                +(p.dob?'<div class=\"p-field\"><span class=\"p-field-l\">DOB</span><span class=\"p-field-v\">'+self.fmtDate(p.dob)+'</span></div>':'')\n                +'</div>'\n                +'<div class=\"p-card-bottom\">'\n                +'<div class=\"p-badges\">'+teamBadges\n                +(p.snpFlag?'<span class=\"p-badge p-badge-snp\">SNP '+self.esc(p.snpFlag)+'</span>':'')\n                +'</div>'\n                +'<span class=\"p-admits-pill\">'+admits.length+' admission'+(admits.length!==1?'s':'')+'</span>'\n                +'<span class=\"p-notes\">'+nc+' note'+(nc!==1?'s':'')+'</span>'\n                +'</div></div>';\n        }).join('');\n        if(this.currentView==='calendar')this.renderCal();\n    },\n\n    // PATIENT MODAL\n    openPatient:function(mid){\n        mid=String(mid);\n        var p=this.patients[mid];\n        if(!p){var keys=Object.keys(this.patients);for(var i=0;i<keys.length;i++){if(String(keys[i])===mid){p=this.patients[keys[i]];break}}}\n        if(!p)return;\n        this.pmPatient=p;this.pmAdmitIdx=0;\n        // Header\n        document.getElementById('pmHeader').innerHTML='<div class=\"pm-name\">'+this.esc(p.name)+'</div><div class=\"pm-details\">'\n            +'<div class=\"pm-item\"><span class=\"pm-lbl\">ID</span><span class=\"pm-val\">'+this.esc(p.memberId)+'</span> <button class=\"pm-copy\" onclick=\"event.stopPropagation();App.copy(\\''+this.esc(p.memberId)+'\\')\">&#9112;</button></div>'\n            +(p.metalTier?'<div class=\"pm-item\"><span class=\"tier-badge tier-'+p.metalTier.toLowerCase()+'\">'+this.esc(p.metalTier)+'</span></div>':'')\n            +(p.dob?'<div class=\"pm-item\"><span class=\"pm-lbl\">DOB</span><span class=\"pm-val\">'+this.esc(p.dob)+'</span></div>':'')\n            +(p.pcp?'<div class=\"pm-item\"><span class=\"pm-lbl\">PCP</span><span class=\"pm-val\">'+this.esc(p.pcp)+'</span></div>':'')\n            +(p.snpFlag?'<div class=\"pm-item\"><span class=\"pm-lbl\">SNP</span><span class=\"pm-val\">'+this.esc(p.snpFlag)+'</span></div>':'')\n            +'</div>';\n        this.renderAdmitList();this.renderAdmitNotes();\n        document.getElementById('patientModal').classList.add('open');document.body.classList.add('no-scroll');\n    },\n    renderAdmitList:function(){\n        var p=this.pmPatient,self=this;\n        var admits=p.admissions.slice().sort(function(a,b){return(b.admitDate||'')>(a.admitDate||'')?1:-1});\n        var ctOpts=CALL_TYPES.map(function(t){return '<option>'+t+'</option>'}).join('');\n        document.getElementById('pmAdmitList').innerHTML=admits.map(function(a,i){\n            var nc=self.notes.filter(function(n){return n.memberId===p.memberId&&n.admission===(a.authNumber||a.admitDate)}).length;\n            var statusOpts='<option value=\"\">—</option>'+CALL_TYPES.map(function(t){return '<option'+(t===a.callType?' selected':'')+'>'+t+'</option>'}).join('');\n            return '<div class=\"admit-card'+(i===self.pmAdmitIdx?' active':'')+'\" onclick=\"App.selectAdmit('+i+')\">'\n                +'<div class=\"admit-dates\">'+(a.admitDate?self.fmtDate(a.admitDate):'No admit date')+' &rarr; '+(a.dcDate?self.fmtDate(a.dcDate):'—')+'</div>'\n                +(a.authNumber?'<div class=\"admit-meta\" style=\"font-family:var(--mono);font-size:10px\">Auth: '+self.esc(a.authNumber)+'</div>':'')\n                +'<div class=\"admit-meta\">'+(a.cm?a.cm:'')+(a.team?' &middot; '+a.team:'')+'</div>'\n                +(a.tocApptDate?'<div class=\"admit-meta\">TOC: '+self.fmtDate(a.tocApptDate)+'</div>':'')\n                +'<div><select class=\"admit-status-sel\" onclick=\"event.stopPropagation()\" onchange=\"App.quickStatus('+i+',this.value)\">'+statusOpts+'</select></div>'\n                +'<div class=\"admit-notes-count\">'+nc+' note'+(nc!==1?'s':'')+'</div>'\n                +'</div>';\n        }).join('');\n        this.pmSortedAdmits=admits;\n    },\n    selectAdmit:function(i){this.pmAdmitIdx=i;this.renderAdmitList();this.renderAdmitNotes();document.getElementById('pmEditPanel').classList.remove('open');document.getElementById('pmEditToggle').textContent='Edit Fields'},\n    quickStatus:function(i,val){\n        if(!this.pmSortedAdmits)return;\n        var a=this.pmSortedAdmits[i];a.callType=val;\n        this.writeAdmission(a);this.render();\n    },\n    toggleEdit:function(){\n        var panel=document.getElementById('pmEditPanel');\n        var btn=document.getElementById('pmEditToggle');\n        if(panel.classList.contains('open')){panel.classList.remove('open');btn.textContent='Edit Fields';return}\n        panel.classList.add('open');btn.textContent='Cancel Edit';\n        var a=this.pmSortedAdmits[this.pmAdmitIdx];if(!a)return;\n        var ctOpts='<option value=\"\">—</option>'+CALL_TYPES.map(function(t){return '<option'+(t===a.callType?' selected':'')+'>'+t+'</option>'}).join('');\n        document.getElementById('pmEditGrid').innerHTML=\n            '<div class=\"pm-edit-field\"><label>Status</label><select id=\"edCT\">'+ctOpts+'</select></div>'\n            +'<div class=\"pm-edit-field\"><label>CM</label><input type=\"text\" id=\"edCM\" value=\"'+App.esc(a.cm||'')+'\"></div>'\n            +'<div class=\"pm-edit-field\"><label>Metal Tier</label><select id=\"edTier\"><option value=\"\">—</option>'+['Gold','Silver','Bronze','Copper','Steel'].map(function(t){return '<option'+(t===a.metalTier?' selected':'')+'>'+t+'</option>'}).join('')+'</select></div>'\n            +'<div class=\"pm-edit-field\"><label>Auth Number</label><input type=\"text\" id=\"edAuth\" value=\"'+App.esc(a.authNumber||'')+'\"></div>'\n            +'<div class=\"pm-edit-field\"><label>Admit Date</label><input type=\"date\" id=\"edAdmit\" value=\"'+(a.admitDate||'')+'\"></div>'\n            +'<div class=\"pm-edit-field\"><label>D/C Date</label><input type=\"date\" id=\"edDC\" value=\"'+(a.dcDate||'')+'\"></div>'\n            +'<div class=\"pm-edit-field\"><label>TOC Appt</label><input type=\"date\" id=\"edTOC\" value=\"'+(a.tocApptDate||'')+'\"></div>'\n            +'<div class=\"pm-edit-field\"><label>PCP</label><input type=\"text\" id=\"edPCP\" value=\"'+App.esc(a.pcp||'')+'\"></div>';\n    },\n    saveEdit:function(){\n        var a=this.pmSortedAdmits[this.pmAdmitIdx];if(!a)return;\n        a.callType=document.getElementById('edCT').value;\n        a.cm=document.getElementById('edCM').value.trim();\n        a.metalTier=document.getElementById('edTier').value.trim();\n        a.authNumber=document.getElementById('edAuth').value.trim();\n        a.admitDate=document.getElementById('edAdmit').value;\n        a.dcDate=document.getElementById('edDC').value;\n        a.tocApptDate=document.getElementById('edTOC').value;\n        var pcp=document.getElementById('edPCP').value.trim();\n        if(this.pmPatient){this.pmPatient.pcp=pcp;this.pmPatient.metalTier=a.metalTier}\n        a.pcp=pcp;\n        this.writeAdmission(a);\n        document.getElementById('pmEditPanel').classList.remove('open');\n        document.getElementById('pmEditToggle').textContent='Edit Fields';\n        // Re-render header\n        this.openPatient(this.pmPatient.memberId);\n        this.render();this.toast('Saved','success');\n    },\n    writeAdmission:function(a){\n        if(!this.wb||!a.teamSheet==null)return;\n        var map=this.map||this.getMap();var c=map.cols;\n        var ws=this.wb.Sheets[this.wb.SheetNames[a.teamSheet]];\n        if(!ws)return;var r=a.xlRow;\n        var set=function(col,val){if(col>=0){var addr=XLSX.utils.encode_cell({r:r,c:col});if(!ws[addr])ws[addr]={};ws[addr].t='s';ws[addr].v=val||''}};\n        set(c.authNumber,a.authNumber);set(c.callType,a.callType);set(c.cm,a.cm);set(c.metalTier,a.metalTier);\n        set(c.admitDate,a.admitDate);set(c.dcDate,a.dcDate);set(c.tocApptDate,a.tocApptDate);set(c.tocKept,a.tocKept);set(c.pcp,a.pcp);\n        this.saveFile();\n    },\n    renderAdmitNotes:function(){\n        if(!this.pmPatient||!this.pmSortedAdmits)return;\n        var a=this.pmSortedAdmits[this.pmAdmitIdx];\n        var admitKey=a?(a.authNumber||a.admitDate):'';\n        var list=this.notes.filter(function(n){return n.memberId===App.pmPatient.memberId&&n.admission===admitKey}).sort(function(a,b){return new Date(b.ts)-new Date(a.ts)});\n        document.getElementById('pmNotesTitle').textContent='Notes — '+(a?this.fmtDate(a.admitDate):'');\n        document.getElementById('pmNotesCount').textContent=list.length+' note'+(list.length!==1?'s':'');\n        var el=document.getElementById('pmNotesList'),self=this;\n        if(!list.length){el.innerHTML='<div class=\"notes-empty\">No notes for this admission.</div>';return}\n        el.innerHTML=list.map(function(n){\n            return '<div class=\"note-card\"><div class=\"note-head\"><span>'+self.fmtTime(n.ts)+'</span><div><button class=\"note-btn note-del\" onclick=\"App.deleteNote(\\''+n.id+'\\')\" title=\"Delete\">&times;</button></div></div><div class=\"note-text\">'+self.esc(n.note)+'</div></div>';\n        }).join('');\n    },\n    addNote:function(){\n        if(!this.pmPatient||!this.pmSortedAdmits)return;\n        var text=document.getElementById('pmNoteInput').value.trim();if(!text)return;\n        var a=this.pmSortedAdmits[this.pmAdmitIdx];\n        this.notes.push({id:String(this.nextNid++),memberId:this.pmPatient.memberId,admission:a?(a.authNumber||a.admitDate):'',ts:new Date().toISOString(),note:text});\n        this.writeNotes();document.getElementById('pmNoteInput').value='';\n        this.renderAdmitNotes();this.renderAdmitList();this.render();\n    },\n    deleteNote:function(nid){if(!confirm('Delete?'))return;this.notes=this.notes.filter(function(n){return n.id!==nid});this.writeNotes();this.renderAdmitNotes();this.renderAdmitList();this.render()},\n    closePM:function(){\n        var text=document.getElementById('pmNoteInput').value.trim();\n        if(text&&this.pmPatient&&this.pmSortedAdmits){var a=this.pmSortedAdmits[this.pmAdmitIdx];this.notes.push({id:String(this.nextNid++),memberId:this.pmPatient.memberId,admission:a?(a.authNumber||a.admitDate):'',ts:new Date().toISOString(),note:text});this.writeNotes();document.getElementById('pmNoteInput').value='';this.render()}\n        this.pmPatient=null;document.getElementById('patientModal').classList.remove('open');document.body.classList.remove('no-scroll');\n        if(this._retCal){this._retCal=false;this.showCalDay()}\n    },\n\n    // VIEW\n    setView:function(v){this.currentView=v;document.querySelectorAll('.vtb').forEach(function(b){b.classList.toggle('active',b.dataset.view===v)});document.getElementById('cardView').style.display=v==='table'?'':'none';document.getElementById('calView').classList.toggle('visible',v==='calendar');if(v==='calendar')this.renderCal()},\n    onSearch:function(v){this.query=v;document.querySelector('.search-wrap').classList.toggle('has-q',!!v);this.render()},\n    clearSearch:function(){document.getElementById('searchInput').value='';this.onSearch('')},\n\n    // CALENDAR\n    fd:function(d){return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0')},\n    calPrev:function(){this.calMonth--;if(this.calMonth<0){this.calMonth=11;this.calYear--}this.calSel=null;this.renderCal()},\n    calNext:function(){this.calMonth++;if(this.calMonth>11){this.calMonth=0;this.calYear++}this.calSel=null;this.renderCal()},\n    calToday:function(){var n=new Date();this.calYear=n.getFullYear();this.calMonth=n.getMonth();this.calSel=this.fd(n);this.renderCal()},\n    renderCal:function(){\n        var y=this.calYear,mo=this.calMonth,self=this;\n        document.getElementById('calTitle').textContent=['January','February','March','April','May','June','July','August','September','October','November','December'][mo]+' '+y;\n        // Build date map from filtered admissions\n        var fp=this.getFilteredPatients();var dm={};\n        fp.forEach(function(r){r.admissions.forEach(function(a){if(!a.dcDate)return;if(!dm[a.dcDate])dm[a.dcDate]={count:0,urg:false,pv:[]};dm[a.dcDate].count++;if(a.callType==='Urgent')dm[a.dcDate].urg=true;if(dm[a.dcDate].pv.length<3)dm[a.dcDate].pv.push(a)})});\n        var first=new Date(y,mo,1).getDay(),days=new Date(y,mo+1,0).getDate(),pd=new Date(y,mo,0).getDate(),today=this.fd(new Date());\n        var h='<div class=\"cal-dh\">Sun</div><div class=\"cal-dh\">Mon</div><div class=\"cal-dh\">Tue</div><div class=\"cal-dh\">Wed</div><div class=\"cal-dh\">Thu</div><div class=\"cal-dh\">Fri</div><div class=\"cal-dh\">Sat</div>';\n        for(var i=first-1;i>=0;i--)h+='<div class=\"cal-d out\"><div class=\"cal-dn\">'+(pd-i)+'</div></div>';\n        for(var d=1;d<=days;d++){\n            var ds=y+'-'+String(mo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');\n            var info=dm[ds];var cls=['cal-d'];if(ds===today)cls.push('today');if(ds===this.calSel)cls.push('sel');\n            var inner='';\n            if(info&&info.count){inner='<div class=\"cal-badge '+(info.urg?'u':'n')+'\">'+info.count+'</div>'+info.pv.map(function(a){return '<div class=\"cal-pv\">'+self.esc(a.name||'').substring(0,16)+'</div>'}).join('');if(info.count>3)inner+='<div class=\"cal-more\">+'+(info.count-3)+'</div>'}\n            h+='<div class=\"'+cls.join(' ')+'\" onclick=\"App.calClick(\\''+ds+'\\')\"><div class=\"cal-dn\">'+d+'</div>'+inner+'</div>';\n        }\n        var rem=(7-((first+days)%7))%7;for(var i=1;i<=rem;i++)h+='<div class=\"cal-d out\"><div class=\"cal-dn\">'+i+'</div></div>';\n        document.getElementById('calGrid').innerHTML=h;\n    },\n    calClick:function(ds){this.calSel=ds;this.renderCal();this.showCalDay()},\n    showCalDay:function(){\n        if(!this.calSel)return;var ds=this.calSel,self=this;\n        var fp=this.getFilteredPatients();var admits=[];\n        fp.forEach(function(r){r.admissions.forEach(function(a){if(a.dcDate===ds)admits.push({patient:r.patient,admission:a})})});\n        if(!admits.length){this.toast('No D/C on '+this.fmtDate(ds),'info');return}\n        document.getElementById('cdTitle').innerHTML=admits.length+' discharge'+(admits.length!==1?'s':'')+' &mdash; '+this.fmtDate(ds);\n        document.getElementById('cdList').innerHTML=admits.map(function(r){\n            return '<div class=\"cd-card\" data-mid=\"'+self.esc(r.patient.memberId)+'\">'\n                +'<div style=\"font-size:15px;font-weight:600;color:var(--t1)\">'+self.esc(r.patient.name)+'</div>'\n                +'<div style=\"font-size:11px;color:var(--t3);margin-top:2px\">'+self.esc(r.patient.memberId)\n                +(r.admission.callType?' &middot; '+self.esc(r.admission.callType):'')\n                +(r.admission.cm?' &middot; '+self.esc(r.admission.cm):'')\n                +(r.admission.team?' &middot; '+r.admission.team:'')\n                +'</div></div>';\n        }).join('');\n        document.getElementById('calDayModal').classList.add('open');document.body.classList.add('no-scroll');\n    },\n    closeCD:function(){document.getElementById('calDayModal').classList.remove('open');document.body.classList.remove('no-scroll')},\n    openFromCal:function(mid){this._retCal=true;document.getElementById('calDayModal').classList.remove('open');this.openPatient(mid)},\n\n    // CSV IMPORT\n    impData:null,impCols:null,impRows:null,impFilterCount:0,\n    startImportCSV:function(){\n        var input=document.createElement('input');input.type='file';input.accept='.csv';\n        var self=this;\n        input.onchange=function(){\n            var file=input.files[0];if(!file)return;\n            file.text().then(function(text){\n                var rows=self.parseCSV(text);\n                self.impCols=rows[0].map(function(x){return x.trim()});\n                self.impRows=rows.slice(1);\n                self.showImportModal();\n            });\n        };\n        input.click();\n    },\n    parseCSV:function(text){\n        var rows=[],row=[],f='',q=false,i=0;\n        while(i<text.length){var ch=text[i];\n            if(q){if(ch==='\"'){if(i+1<text.length&&text[i+1]==='\"'){f+='\"';i+=2}else{q=false;i++}}else{f+=ch;i++}}\n            else{if(ch==='\"'){q=true;i++}else if(ch===','){row.push(f);f='';i++}else if(ch==='\\r'){i++}else if(ch==='\\n'){row.push(f);f='';if(row.length>1||row.some(function(x){return x.trim()}))rows.push(row);row=[];i++}else{f+=ch;i++}}\n        }\n        if(f||row.length){row.push(f);rows.push(row)}return rows;\n    },\n    showImportModal:function(){\n        var cols=this.impCols,self=this,map=this.map||this.getMap();\n        // Team dropdown\n        var teamOpts=map.teams.map(function(t){return '<option value=\"'+t.sheet+'\">'+self.esc(t.name)+'</option>'}).join('');\n        document.getElementById('impTeam').innerHTML=teamOpts;\n        // Build mappings\n        var impFields=this.fields.slice(); // same fields as excel mapping\n        var html=impFields.map(function(f){\n            var best=-1;\n            cols.forEach(function(c,i){var cl=c.toLowerCase();if(best===-1&&f.hints.some(function(h){return cl.indexOf(h)>-1}))best=i});\n            var opts='<option value=\"-1\">-- Skip --</option>'+cols.map(function(c,i){return '<option value=\"'+i+'\"'+(i===best?' selected':'')+'>'+self.esc(c)+'</option>'}).join('');\n            return '<div class=\"fi\"><label>'+f.label+'</label><select id=\"imp_'+f.key+'\">'+opts+'</select></div>';\n        }).join('');\n        document.getElementById('impMappings').innerHTML=html;\n        document.getElementById('impFilters').innerHTML='<div style=\"color:var(--t3);font-size:12px\">No filters — all rows imported</div>';\n        this.impFilterCount=0;\n        document.getElementById('impPreview').textContent=this.impRows.length+' rows ready';\n        document.getElementById('importModal').classList.add('open');document.body.classList.add('no-scroll');\n    },\n    hideImport:function(){document.getElementById('importModal').classList.remove('open');document.body.classList.remove('no-scroll')},\n    addImpFilter:function(){\n        var self=this,cols=this.impCols;\n        var id='impF_'+(this.impFilterCount++);\n        var colOpts=cols.map(function(c,i){return '<option value=\"'+i+'\">'+self.esc(c)+'</option>'}).join('');\n        var div=document.createElement('div');div.id=id;div.style.cssText='display:flex;gap:6px;align-items:center;margin-bottom:6px';\n        div.innerHTML='<select class=\"impFCol\" style=\"flex:1;padding:4px 6px;font-size:12px;border:1px solid var(--bd);border-radius:4px\">'+colOpts+'</select>'\n            +'<select class=\"impFOp\" style=\"padding:4px 6px;font-size:12px;border:1px solid var(--bd);border-radius:4px\"><option>equals</option><option>contains</option><option>not equals</option></select>'\n            +'<input class=\"impFVal\" style=\"flex:1;padding:4px 6px;font-size:12px;border:1px solid var(--bd);border-radius:4px\" placeholder=\"value\">'\n            +'<button class=\"btn btn-sm\" onclick=\"this.parentNode.remove();App.updateImpPreview()\" style=\"color:var(--red)\">&times;</button>';\n        var container=document.getElementById('impFilters');\n        if(this.impFilterCount===1)container.innerHTML='';\n        container.appendChild(div);\n        div.querySelector('.impFCol').onchange=div.querySelector('.impFOp').onchange=div.querySelector('.impFVal').oninput=function(){self.updateImpPreview()};\n    },\n    getImpFilteredRows:function(){\n        var rows=this.impRows.slice();\n        var filters=document.querySelectorAll('#impFilters > div');\n        filters.forEach(function(f){\n            var col=parseInt(f.querySelector('.impFCol').value);\n            var op=f.querySelector('.impFOp').value;\n            var val=f.querySelector('.impFVal').value.trim().toLowerCase();\n            if(!val)return;\n            rows=rows.filter(function(r){\n                var cv=(r[col]||'').trim().toLowerCase();\n                if(op==='equals')return cv===val;if(op==='contains')return cv.indexOf(val)>-1;return cv!==val;\n            });\n        });\n        return rows;\n    },\n    updateImpPreview:function(){document.getElementById('impPreview').textContent=this.getImpFilteredRows().length+' of '+this.impRows.length+' rows match'},\n    runImport:function(){\n        if(!this.impRows)return;\n        var self=this,c={},map=this.map||this.getMap();\n        this.fields.forEach(function(f){c[f.key]=parseInt(document.getElementById('imp_'+f.key).value)});\n        var teamSheet=parseInt(document.getElementById('impTeam').value);\n        var teamName='';map.teams.forEach(function(t){if(t.sheet===teamSheet)teamName=t.name});\n        var rows=this.getImpFilteredRows();\n        var added=0,updated=0,skipped=0;\n        // Build auth lookup\n        var authMap={};this.admissions.forEach(function(a){if(a.authNumber)authMap[a.authNumber]=a});\n        rows.forEach(function(r){\n            var auth=c.authNumber>=0?(r[c.authNumber]||'').trim():'';\n            var mid=c.memberId>=0?(r[c.memberId]||'').trim():'';\n            if(!mid){skipped++;return}\n            var last=c.lastName>=0?(r[c.lastName]||'').trim():'';\n            var first=c.firstName>=0?(r[c.firstName]||'').trim():'';\n            var name=last&&first?last+', '+first:(last||first);\n            if(auth&&authMap[auth]){\n                // Existing admission — update fields but keep status\n                var ex=authMap[auth];\n                if(name)ex.name=name;if(last)ex.lastName=last;if(first)ex.firstName=first;\n                if(c.metalTier>=0){var mt=(r[c.metalTier]||'').trim();if(mt)ex.metalTier=mt}\n                if(c.pcp>=0){var pc=(r[c.pcp]||'').trim();if(pc)ex.pcp=pc}\n                if(c.cm>=0){var cm=(r[c.cm]||'').trim();if(cm)ex.cm=cm}\n                if(c.admitDate>=0){var ad=self.parseDate(r[c.admitDate]);if(ad)ex.admitDate=ad}\n                if(c.dcDate>=0){var dc=self.parseDate(r[c.dcDate]);if(dc)ex.dcDate=dc}\n                self.writeAdmission(ex);updated++;\n            }else{\n                // New admission — add to team sheet with status \"Added Today\"\n                var ws=self.wb.Sheets[self.wb.SheetNames[teamSheet]];\n                var range=XLSX.utils.decode_range(ws['!ref']||'A1');\n                var newRow=range.e.r+1;\n                var mc=map.cols;\n                var set=function(col,val){if(col>=0){var addr=XLSX.utils.encode_cell({r:newRow,c:col});ws[addr]={t:'s',v:val||''}}};\n                set(mc.authNumber,auth);set(mc.memberId,mid);set(mc.lastName,last);set(mc.firstName,first);\n                set(mc.metalTier,c.metalTier>=0?(r[c.metalTier]||'').trim():'');\n                set(mc.snpFlag,c.snpFlag>=0?(r[c.snpFlag]||'').trim():'');\n                set(mc.pcp,c.pcp>=0?(r[c.pcp]||'').trim():'');\n                set(mc.dob,c.dob>=0?(r[c.dob]||'').trim():'');\n                set(mc.callType,'Added Today');\n                set(mc.cm,c.cm>=0?(r[c.cm]||'').trim():'');\n                set(mc.admitDate,c.admitDate>=0?self.parseDate(r[c.admitDate]):'');\n                set(mc.dcDate,c.dcDate>=0?self.parseDate(r[c.dcDate]):'');\n                set(mc.tocApptDate,'');set(mc.tocKept,'');\n                range.e.r=newRow;ws['!ref']=XLSX.utils.encode_range(range);\n                added++;\n            }\n        });\n        this.saveFile();this.loadData();this.hideImport();\n        var msg=added+' added';if(updated)msg+=', '+updated+' updated';if(skipped)msg+=', '+skipped+' skipped';\n        this.toast(msg,'success');\n    },\n\n    // INLINE POPOVERS\n    closePop:function(){var p=document.getElementById('inlinePop');if(p)p.remove()},\n    showPop:function(anchor,html){\n        this.closePop();\n        var rect=anchor.getBoundingClientRect();\n        var div=document.createElement('div');div.id='inlinePop';div.className='pop';div.innerHTML=html;\n        document.body.appendChild(div);\n        div.style.top=Math.min(rect.bottom+4,window.innerHeight-div.offsetHeight-8)+'px';\n        div.style.left=Math.min(rect.left,window.innerWidth-div.offsetWidth-8)+'px';\n        setTimeout(function(){document.addEventListener('click',function close(e){if(!div.contains(e.target)){div.remove();document.removeEventListener('click',close)}})},0);\n    },\n    showStatusPop:function(el,ri){\n        var a=this.admissions[ri];if(!a)return;\n        var self=this;\n        var items=CALL_TYPES.map(function(t){return '<div class=\"pop-item'+(t===a.callType?' active':'')+'\" onclick=\"App.setStatus('+ri+',\\''+self.esc(t)+'\\')\">'+self.esc(t)+'</div>'}).join('');\n        this.showPop(el,items);\n    },\n    setStatus:function(ri,val){\n        var a=this.admissions[ri];if(!a)return;\n        a.callType=val;this.writeAdmission(a);this.closePop();this.render();\n    },\n    showDatePop:function(el,ri){\n        var a=this.admissions[ri];if(!a)return;\n        this.showPop(el,'<div class=\"pop-date\"><input type=\"date\" value=\"'+(a.tocApptDate||'')+'\" onchange=\"App.setTocDate('+ri+',this.value)\"></div>');\n    },\n    setTocDate:function(ri,val){\n        var a=this.admissions[ri];if(!a)return;\n        a.tocApptDate=val;this.writeAdmission(a);this.closePop();this.render();\n    },\n    showKeptPop:function(el,ri){\n        var a=this.admissions[ri];if(!a)return;\n        var self=this,opts=['Expected','Kept','No Show','Cancelled'];\n        var items=opts.map(function(o){return '<div class=\"pop-item'+(o===a.tocKept?' active':'')+'\" onclick=\"App.setKept('+ri+',\\''+o+'\\')\">'+o+'</div>'}).join('');\n        this.showPop(el,items);\n    },\n    setKept:function(ri,val){\n        var a=this.admissions[ri];if(!a)return;\n        a.tocKept=val;this.writeAdmission(a);this.closePop();this.render();\n    },\n\n    init:function(){\n        document.addEventListener('keydown',function(e){if(e.key==='Escape'){if(document.getElementById('calDayModal').classList.contains('open'))App.closeCD();else if(document.getElementById('patientModal').classList.contains('open'))App.closePM()}});\n        document.addEventListener('click',function(e){\n            var card=e.target.closest('[data-mid]');\n            if(card&&card.classList.contains('p-card')){App.openPatient(card.getAttribute('data-mid'));return}\n            if(card&&card.classList.contains('cd-card')){App.openFromCal(card.getAttribute('data-mid'));return}\n        });\n    }\n};\nwindow.App=App;\nApp.init();\n</script>\n</body>\n</html>\n";
